\frac{u-u_{j}}{u_{j+k_{u}-1}-u_{j}} B_{j, k_{u}-1}(u)+\frac{u_{j+k_{u}}-u}{u_{j+k_{u}}-u_{j+1}} B_{j+1, k_{u}-1}(u) & \text { otherwise } \\
